const seen = new Set();
for (let i = 0; i < 5000; i++) {
  const dice = Math.floor(Math.random() * 6) + 1;
  if (!Number.isInteger(dice) || dice < 1 || dice > 6) ok = false;
  seen.add(dice);
}
console.log(ok, seen.size);
